/* eslint-disable @stylistic/max-len */

import type { ArchiveMime, ImageMime } from '$types';

const imageTypeTests: Record<ImageMime, string> = {
	'image/jpeg': '/9j/4AAQSkZJRgABAQEASABIAAD/2wBDAP//////////////////////////////////////////////////////////////////////////////////////wgALCAABAAEBAREA/8QAFBABAAAAAAAAAAAAAAAAAAAAAP/aAAgBAQABPxA=',
	'image/png': 'R0lGODlhAQABAIAAAP///wAAACwAAAAAAQABAAACAkQBADs',
	'image/webp': 'UklGRiIAAABXRUJQVlA4IBYAAAAwAQCdASoBAAEADsD+JaQAA3AAAAAA',
	'image/apng': 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAFoEvQfAAAACXBIWXMAAA7DAAAOwwHHb6hkAAAACGFjVEwAAAABAAAAALQt6aAAAAAaZmNUTAAAAAAAAAABAAAAAQAAAAAAAAAAAAEAZAEAAS3nuwAAAAxJREFUeJxiYIAAAAAAAP//35uwWgAAAAZJREFUAwAACAABz3YKQAAAAABJRU5ErkJggg==',
	'image/bmp': 'Qk06AAAAAAAAADYAAAAoAAAAAQAAAAEAAAABABgAAAAAAAQAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA==',
	'image/avif': '',
	'image/gif': 'R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7',
	'image/tiff': '',
	'image/x-icon': '',
	'image/heif': '',
} as const;

const duplicateMimes: { [K in ImageMime]?: string[] } = {
	'image/jpeg': ['image/pjpeg'],
	'image/bmp': ['image/x-bmp'],
	'image/tiff': ['image/tiff-fx'],
	'image/x-icon': ['image/ico', 'image/vnd.microsoft.icon', 'image/icon', 'text/ico', 'application/ico'],
	'image/heif': ['image/heif', 'image/heif-sequence', 'image/heic', 'image/heic-sequence'],
};

let imageInputs = $state<ImageMime[]>([]);
let imageOutputs = $state<ImageMime[]>([]);

const archiveInputs: ArchiveMime[] = ['application/zip', 'application/gzip'];

export default {
	get imageInputs() {
		return imageInputs;
	},
	get imageOutputs() {
		return imageOutputs;
	},
	get archiveInputs() {
		return archiveInputs;
	},

	async testImageInputs () {
		imageInputs = (await Promise.all(
			Object.entries(imageTypeTests).map(async ([_mimetype, base64]) => {
				const mimetype = _mimetype as ImageMime;
				const url = `data:${mimetype};base64,${base64}`;
				const image = new Image();
				image.src = url;
				const supported = await new Promise<boolean>((resolve) => {
					image.onload = () => resolve(true);
					image.onerror = () => resolve(false);
				});

				if (!supported) {
					return null;
				}

				const fallbackMimes = duplicateMimes[mimetype];
				return [mimetype, ...(fallbackMimes ? fallbackMimes as ImageMime[] : [])];
			}),
		)).flat().filter((value) => value !== null);

		return imageInputs;
	},
	testImageOutputs () {
		imageOutputs = Object.entries(imageTypeTests).map(([mimetype]) => {
			const url = document.createElement('canvas').toDataURL(mimetype);
			if (url.startsWith(`data:${mimetype}`)) {
				return mimetype as ImageMime;
			}
			return null;
		}).filter((mimeType) => mimeType !== null);
	},
};
